import java.io.*;
import java.util.*;

import org.apache.commons.text.StringEscapeUtils; // Import Apache Commons Text library for HTML escaping

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize user input using HTML escaping
        String sanitizedName = StringEscapeUtils.escapeHtml4(name);

        // Display sanitized input to prevent XSS attacks
        System.out.println("Hello, " + sanitizedName + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
